import { useParams } from "react-router-dom";
import { GetFixtures } from "../services/fixture-service";
import { useEffect, useState } from "react";
import { Fixture } from "../objects/fixture";
import FixtureTable from "../components/fixture/fixture-table";
import SeasonSummaryTable from "../components/season/season-summary-table";
import { GameType } from "../objects/enums/enums";
import { GetSeasonGameStats } from "../services/game-stat-service";
import { GameStat } from "../objects/game-stat";
import GameStatTable from "../components/game-stats/game-stat-table";

export default function FixturesPage()
{
    const param = useParams();
    const [fixtures, setFixtures] = useState<Fixture[] | null>(null);
    const [gameStats, setGameStats] = useState<GameStat[] | null>(null);

    useEffect(() => {
        GetFixtures(param.id).then(fixture => setFixtures(fixture));
    }, [param.id]);  
    
    useEffect(() => {
        GetSeasonGameStats(param.id).then(gameStats => setGameStats(gameStats));
    }, [param.id]);
    
    return(        
        <div>
            { fixtures ? 
                <>  
                    <div className="row">
                        <h2>{fixtures.at(0)?.seasonName}</h2>
                    </div>
                    <div className="row">
                        <div className="col-1"></div>
                        <div className="col-10">                            
                            <h2>League</h2>
                            <SeasonSummaryTable fixtures={fixtures} gameType={GameType.League}></SeasonSummaryTable>
                            <FixtureTable fixtures={fixtures} gameType={GameType.League}></FixtureTable>                             
                        </div>
                    </div>                     
                    <div className="row">
                        <div className="col-1"></div>
                        <div className="col-10">
                            <h2>Friendlies</h2>
                            <SeasonSummaryTable fixtures={fixtures} gameType={GameType.Friendly}></SeasonSummaryTable>
                            <FixtureTable fixtures={fixtures} gameType={GameType.Friendly}></FixtureTable> 
                        </div>
                    </div>                   
                </> 
                : <p>Loading...</p>}

            <div className="row">
                {   gameStats ? <GameStatTable gameStats={gameStats}></GameStatTable>
                    : <p>Loading Stats...</p>}
            </div>
        </div>                
    )
}
